arguments.argument:
if global.gamePaused=false
{
  if rockProg=0
  {
    symbolBeep+=1
    if symbolBeep mod 4=0
    {
      if warnSymbol=0 {warnSymbol=1}
      else {warnSymbol=0}
    }
    
    warnTime-=1
    if warnTime=0
    {
      warnSymbol=0
      rockProg=1
    }
  }
  else if rockProg=1
  {
    warnTime+=1
    if warnTime>=5
    {
      x-=rockSpd
      
      if bumpProg=0 and x<=384
      {
        playSound(global.snd_MarioCannon,0,0.94,31000)
        playSound(global.snd_LampOn,0,1,13000)
        (GID(465774)).jumpProg=1;
        bumpProg=1
      }
      else if bumpProg=1 and x<=192
      {
        playSound(global.snd_MarioCannon,0,0.94,31000)
        playSound(global.snd_LampOn,0,1,13000)
        (GID(465773)).jumpProg=1;
        bumpProg=2
      }
      if x<=-16
      {
        instance_destroy()
      }
    }
  }
}
